import React, { useEffect, useState } from 'react';
import { Card, Table, Button } from 'react-bootstrap';
import { getExpiries, triggerExpiryNotifications } from '../api';
import { toast } from 'react-toastify';

const ExpiryDashboard = () => {
  const [expiries, setExpiries] = useState([]);
  const [loading, setLoading] = useState(false);

  const load = async () => {
    setLoading(true);
    try {
      const res = await getExpiries();
      if (res.data && res.data.data) {
        setExpiries(res.data.data);
      }
    } catch (err) {
      console.error(err);
      toast.error('Failed to load expiry data');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const handleTrigger = async () => {
    try {
      const res = await triggerExpiryNotifications();
      toast.info(res.data?.message || 'Triggered');
    } catch (err) {
      toast.error('Failed to trigger notifications');
    }
  };

  return (
    <Card>
      <Card.Header className="d-flex justify-content-between align-items-center">
        <strong>Expiry Tracking & Notifications</strong>
        <div>
          <Button variant="outline-primary" size="sm" onClick={load} className="me-2">Refresh</Button>
          <Button variant="primary" size="sm" onClick={handleTrigger}>Send Now</Button>
        </div>
      </Card.Header>
      <Card.Body>
        {loading ? (
          <p>Loading...</p>
        ) : (
          <Table hover responsive>
            <thead>
              <tr>
                <th>Document</th>
                <th>Employee</th>
                <th>Type</th>
                <th>Expiry Date</th>
                <th>Days Left</th>
              </tr>
            </thead>
            <tbody>
              {expiries.length === 0 ? (
                <tr>
                  <td colSpan={5} className="text-center text-muted">No expiring documents in configured window</td>
                </tr>
              ) : (
                expiries.map(e => (
                  <tr key={e.id}>
                    <td>{e.docId} - {e.fileName}</td>
                    <td>{e.employeeName} ({e.employeeId})</td>
                    <td>{e.documentType}</td>
                    <td>{e.expiryDate}</td>
                    <td>{e.daysLeft}</td>
                  </tr>
                ))
              )}
            </tbody>
          </Table>
        )}
      </Card.Body>
    </Card>
  );
};

export default ExpiryDashboard;
